private byte[] compTweak(String vId, int mode, int lambda, int outLen, int sLen, byte[] aData) {
    byte[] modeByte = new byte[1];
    byte[] lambdaByte = new byte[1];
    byte[] outLenByte = this.helper.intToByteArrayLittleEndian(outLen, 2);
